func appendJSON(dst []byte, j []byte) []byte {
	return append(dst, j...)
}
func appendCBOR(dst []byte, cbor []byte) []byte {
	dst = append(dst, []byte("\"data:application/cbor;base64,")...)
	l := len(dst)
	enc := base64.StdEncoding
	n := enc.EncodedLen(len(cbor))
	for i := 0; i < n; i++ {
		dst = append(dst, '.')
	}
	enc.Encode(dst[l:], cbor)
	return append(dst, '"')
}

